  ('judicial-4d3895b1-moex-00054', 'judicial-4d3895b1', 'judicial-4d3895b1-moex-112-98c44bb8', 'sub-judicial-4d3895b1-03', NULL, 'essay', '德國人 A 住於臺北，受僱於我國 B 軟體公司，雙方契約中約定 A 於任
職 B 軟體公司期間之電腦程式軟體創作（系爭軟體），其權利歸屬雙方
共有。契約並約定以新臺幣結算薪資跟系爭軟體出售之權利金。但契約
並未約定契約之準據法。
其後 A 欲離職返回德國，B 雖未拖欠薪資，但 B 不願意結算權利金給
A。B主張，依據我國法律規定，A職務上之創作，權利應該屬於B。試
依我國現行涉外民事法律適用法之規定，回答以下問題：
該契約之準據法為何？（13 分）
系爭軟體權利歸屬，其準據法為何？（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:27+00:00", "source_pdf_sha1": "bd4b4bf30f45", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "101", "s": "0416", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與國際私法", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公證人"}'::jsonb, NULL)
